// // If fz is 11, then a is 0.
// If fz is 00, then a is 0.
// If fz is 01, then a is 1.
// If fz is 10, then a is 1.
module top_module (
    input f,
    input z,
    output reg a
);
    always @(*) begin
        case ({f, z})
            2'b11: a = 1'b1;
            2'b00: a = 1'b1;
            2'b01: a = 1'b0;
            2'b10: a = 1'b0;
        endcase
    end
endmodule

